int countOccurrences(const std::vector<std::string>& lines, const std::string& word) {
    int count = 0;
    for (const std::string& line : lines) {
        if (std::count(line.begin(), line.end(), word[0]) == line.length() - word.length() + 1 && word == line.substr(1)) {
            count++;
        }
    }
    return count;
}
```
Finally, define a main function to read the text file, count occurrences, and print the result:
```cpp
